SELECT import_statement, COUNT(*) AS import_count FROM (SELECT TRIM(SUBSTRING(sc."content", POSITION('import ' IN sc."content") + 7)) AS import_statement FROM "GITHUB_REPOS"."SAMPLE_CONTENTS" sc JOIN "GITHUB_REPOS"."SAMPLE_FILES" sf ON sf."id" = sc."id" WHERE sf."path" ILIKE '%.py' OR sf."path" ILIKE '%.r' OR sf."path" ILIKE '%.R' OR sf."path" ILIKE '%.Rmd' OR sf."path" ILIKE '%.rmd' OR sf."path" ILIKE '%.ipynb') AS subquery GROUP BY import_statement ORDER BY import_count DESC LIMIT 1 OFFSET 1; /* Get the second most frequently imported library/module */
